
-- Add conditional passport section to New Booking Confirmation template
UPDATE email_templates 
SET content_template = '<p>Dear {{customer_first_name}} {{customer_last_name}},</p><p>Thanks for booking on our <strong>{{tour_name}}, </strong>we have now received your deposit and locked in your spot.</p><p>Please review your booking details below and advise us promptly if any information requires updating. You may also <a href="{{profile_update_link}}" rel="noopener noreferrer" target="_blank"><strong>update your profile here</strong></a> with any dietary, emergency contact, or other important information.</p><p>{{#passenger_2_missing_email}}</p><p>If you haven''t already, please let us know your travel partner''s contact email and phone number so they can also be informed of all tour updates.</p><p>{{/passenger_2_missing_email}}</p><p><strong>TOUR DETAILS</strong></p><ul><li><strong>{{tour_name}}</strong></li><li>Location: {{tour_location}}</li><li>Tour dates: {{tour_start_date}} - {{tour_end_date}}</li><li>Duration: {{tour_days}} days, {{tour_nights}} nights</li></ul><p><strong>PASSENGER INFORMATION</strong></p><ul><li>Lead Passenger: <strong>{{lead_passenger_first_name}} {{lead_passenger_last_name}}</strong></li><li>Preferred Name: {{lead_passenger_preferred_name}}</li><li><span style="color: rgb(0, 31, 61);">Passenger 2: </span><strong style="color: rgb(0, 31, 61);">{{passenger_2_first_name}} {{passenger_2_last_name}}</strong></li><li>Total Passengers: {{booking_passenger_count}}</li><li>Phone Number: {{customer_phone}}</li><li>Dietary Requirements: {{lead_passenger_dietary_requirements}}, {{passenger_2_dietary_requirements}}</li><li>Accessibilty Needs: {{lead_passenger_accessibility_needs}}, {{passenger_2_accessibility_needs}}</li><li>EMERGENCY CONTACT: {{customer_emergency_contact_name}} {{customer_emergency_contact_phone}}</li></ul><p class="ql-align-center">{{profile_update_button}}</p><p>{{#needs_passport_submission}}</p><p><strong>PASSPORT DETAILS REQUIRED</strong></p><p>This tour requires passport details for all travelling passengers. Please submit yours at your earliest convenience using the button below.</p><p class="ql-align-center">{{travel_docs_button}}</p><p>{{/needs_passport_submission}}</p><p><strong>ACCOMMODATION</strong></p><p>{{#hotel_bookings}}</p><ul><li>Hotel: <strong>{{hotel_name}}</strong></li><li>Check In: {{hotel_check_in_date}}</li><li>Check Out: {{hotel_check_out_date}}</li><li>Nights: {{hotel_nights}}</li><li>Room Type: {{hotel_room_type}}</li><li>Room Bedding: {{hotel_bedding}}</li></ul><p>{{/hotel_bookings}}</p><p>You will receive further updates in the lead-up to the tour. The final guest information pack will be emailed two weeks before the tour starts. Inside you''ll find everything you need - your day-by-day schedule, dress codes, and all the important details to help you prepare for your trip.</p><p>If you have any other questions, don''t hesitate to ask.</p><p>Best regards,</p><p>ART Team</p>',
    updated_at = now()
WHERE id = '096bd741-d4de-4c57-82ca-caa0ece55cbb';

-- Add conditional passport section to 100 Day Confirmation template
UPDATE email_templates 
SET content_template = '<p>Dear {{customer_first_name}} {{customer_last_name}},</p><p>We look forward to welcoming you on our <strong>{{tour_name}}, </strong>in just over three month''s time.</p><p>If you have yet to pay your final balance, your invoice will be issued shortly.</p><p>Review your booking details below and advise us promptly if any information requires updating or if you require any additional nights'' accommodation.</p><p>Please review your personal details and use the <a href="{{profile_update_link}}" rel="noopener noreferrer" target="_blank"><strong>button below</strong></a> to update emergency contacts, dietary requirements, or any other important information.</p><p><strong>TOUR DETAILS</strong></p><ul><li><strong>{{tour_name}}</strong></li><li>Location: {{tour_location}}</li><li>Tour dates: {{tour_start_date}} - {{tour_end_date}}</li><li>Duration: {{tour_days}} days, {{tour_nights}} nights</li></ul><p><strong>PASSENGER INFORMATION</strong></p><ul><li>Lead Passenger: <strong>{{lead_passenger_first_name}} {{lead_passenger_last_name}}</strong></li><li>Preferred Name: {{lead_passenger_preferred_name}}</li><li>Total Passengers: {{booking_passenger_count}}</li><li>Passenger 2: <span style="color: rgb(0, 31, 61);"> </span><strong style="color: rgb(0, 31, 61);">{{passenger_2_first_name}} {{passenger_2_last_name}}</strong></li><li><span style="color: rgb(0, 31, 61);">Phone Number: {{customer_phone}}</span></li><li>Dietary Requirements: {{lead_passenger_dietary_requirements}}, {{passenger_2_dietary_requirements}}</li><li>Accessibilty Needs: {{lead_passenger_accessibility_needs}}, {{passenger_2_accessibility_needs}}</li><li>EMERGENCY CONTACT: {{customer_emergency_contact_name}} {{customer_emergency_contact_phone}}</li></ul><p class="ql-align-center">{{profile_update_button}}</p><p>{{#needs_passport_submission}}</p><p><strong>PASSPORT DETAILS REQUIRED</strong></p><p>We still require your passport details for this tour. Please submit them using the button below.</p><p class="ql-align-center">{{travel_docs_button}}</p><p>{{/needs_passport_submission}}</p><p>{{#missing_pickup_selection}}</p><p><strong>PICKUP LOCATION REQUIRED</strong></p><p>Please select your preferred pickup location for the tour using the button below.</p><p class="ql-align-center">{{pickup_button}}</p><p>{{/missing_pickup_selection}}</p><p><strong>ACCOMMODATION</strong></p><p>{{#hotel_bookings}}</p><ul><li>Hotel: <strong>{{hotel_name}}</strong></li><li>Check In: {{hotel_check_in_date}}</li><li>Check Out: {{hotel_check_out_date}}</li><li>Nights: {{hotel_nights}}</li><li>Room Type: {{hotel_room_type}}</li><li>Room Bedding: {{hotel_bedding}}</li></ul><p>{{/hotel_bookings}}</p><p>A guest information pack will be emailed to you shortly. Inside you''ll find everything you need - your day-by-day schedule, dress codes, and all the important details to help you prepare for your trip.</p><p>If you have any other questions, don''t hesitate to ask.</p><p>Best regards,</p><p>ART Team</p>',
    updated_at = now()
WHERE id = '88ff00b5-f7c1-4d9e-9955-56d4e98d27da';
